beforeSaveCustomScript:
bookingAddressStreet = contact.addressStreet;
bookingAddressCity = contact.addressCity;
bookingAddressCountry = contact.addressCountry;
bookingAddressState = contact.addressState;
bookingAddressPostalCode = contact.addressPostalCode;

firstNameTpl = firstName;

passportDetails = string\concatenate(
    ifThenElse(fullNameonPassport, string\concatenate('Full Name on Passport: ', fullNameonPassport, '\n'), ''),
    ifThenElse(passportNumber, string\concatenate('Passport Number: ', passportNumber, '\n'), ''),
    ifThenElse(passportCountry, string\concatenate('Passport Country: ', passportCountry, '\n'), ''),
    ifThenElse(
        passportExpirationDate != null && passportExpirationDate != '' && passportExpirationDate != '0000-00-00',
        string\concatenate('Expiration Date: ', datetime\format(passportExpirationDate, 'MMM d, YYYY'), '\n'),
        ''
    )
);

firstEmergencyContact = string\concatenate(
    ifThenElse(firstEmergencyContactName, string\concatenate('Name: ', firstEmergencyContactName, '\n'), ''),
    ifThenElse(firstEmergencyContactRelationship, string\concatenate('Relationship: ', firstEmergencyContactRelationship, '\n'), ''),
    ifThenElse(firstEmergencyContactEmail, string\concatenate('Email: ', firstEmergencyContactEmail, '\n'), ''),
    ifThenElse(firstEmergencyContactPhone, string\concatenate('Phone: ', firstEmergencyContactPhone, '\n'), '')
);

secondEmergencyContact = string\concatenate(
    ifThenElse(secondEmergencyContactName, string\concatenate('Name:', secondEmergencyContactName, '\n'), ''),
    ifThenElse(secondEmergencyContactRelationship, string\concatenate('Relationship: ', secondEmergencyContactRelationship, '\n'), ''),
    ifThenElse(secondEmergencyContactEmail, string\concatenate('Email: ', secondEmergencyContactEmail, '\n'), ''),
    ifThenElse(secondEmergencyContactPhone, string\concatenate('Phone: ', secondEmergencyContactPhone, '\n'), '')
);

bookingId = string\concatenate(
    'BK-',
    ifThenElse(
        tourName != '',
        tourName,
        'NO-TOUR'
    ),
    '-',
    ifThenElse(
        name != '',
        name,
        'NO-NAME'
    )
);

name = string\concatenate(
    ifThenElse(firstName, firstName, ''),
    ifThenElse(firstName != '' && lastName != '', ' ', ''),
    ifThenElse(lastName, lastName, '')
);


ifThen(
    depositLinkedCount > 0,
    hasDeposit = true,
    hasDeposit = false
);
